"use strict";parserFactory.register("truyenfull.vision",()=>new TruyenFullVisionParser);class TruyenFullVisionParser extends Parser{constructor(){super()}getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,TruyenFullVisionParser.extractPartialChapterList,TruyenFullVisionParser.getUrlsOfTocPages,t)}static getUrlsOfTocPages(e){let t=[],r=e.querySelector("input#total-page");if(!r)return t;let a=parseInt(r.getAttribute("value"),10),l=new URL(e.baseURI),n=l.pathname.replace(/\/trang-\d+\/?$/,"");n.endsWith("/")||(n+="/");for(let e=2;e<=a;++e){let r=new URL(l);r.hash="",r.search="",r.pathname=n+`trang-${e}/`,t.push(r.toString())}return t}static extractPartialChapterList(e){return[...e.querySelectorAll("ul.list-chapter a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.chapter-c")}extractTitleImpl(e){return e.querySelector("h3.title")}extractAuthor(e){let t=e.querySelector("a[itemprop='author']");return t?.textContent??super.extractAuthor(e)}extractLanguage(e){return e.querySelector("html").getAttribute("lang")}extractDescription(e){return e.querySelector(".desc-text").textContent.trim()}findChapterTitle(e){let t=e.querySelector("a.chapter-title");return null===t?super.findChapterTitle(e):t.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.desc-text")]}}